#include <stdio.h>
#include <stdlib.h>
#define MOD 998244353

long long factorial(int n) {
    long long result = 1;
    for (int i = 2; i <= n; i++) {
        result = (result * i) % MOD;
    }
    return result;
}

long long modInverse(long long a) {
    long long m = MOD;
    long long m0 = m;
    long long y = 0, x = 1;
    if (m == 1)
        return 0;
    while (a > 1) {
        long long q = a / m;
        long long t = m;
        m = a % m, a = t;
        t = y;
        y = x - q * y;
        x = t;
    }
    if (x < 0)
        x += m0;
    return x;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        long long result = factorial(N);
        int* freq = (int*)calloc(N + 1, sizeof(int));
        for (int i = 0; i < N; i++) {
            freq[A[i]]++;
        }
        for (int i = 1; i <= N; i++) {
            if (freq[i] > 0) {
                result = (result * factorial(freq[i])) % MOD;
                result = (result * modInverse(factorial(i))) % MOD;
            }
        }
        printf("%lld\n", result);
        free(A);
        free(freq);
    }
    return 0;
}

